// Rate limiting - simple in-memory implementation
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 30;

function rateLimit(req, res, next) {
  const token = req.headers.authorization || req.ip;
  const now = Date.now();

  if (!rateLimitMap.has(token)) {
    rateLimitMap.set(token, []);
  }

  const timestamps = rateLimitMap.get(token).filter(t => now - t < RATE_LIMIT_WINDOW_MS);
  timestamps.push(now);
  rateLimitMap.set(token, timestamps);

  if (timestamps.length > RATE_LIMIT_MAX_REQUESTS) {
    return res.status(429).json({ error: 'Rate limit exceeded. Try again later.' });
  }

  next();
}

// Periodically clean up rate limit map
